def min_kbeautiful_with_digits(n_str, digits):
    # digits is a sorted list of allowed digits (as chars)
    # Find minimum number >= n_str using only these digits, same length
    length = len(n_str)
    result = []

    def solve(pos, tight):
        if pos == length:
            return []
        d = n_str[pos]
        if tight:
            # find smallest digit in digits >= d
            for c in digits:
                if c > d:
                    # fill rest with smallest digit
                    return [c] + [digits[0]] * (length - pos - 1)
                elif c == d:
                    rest = solve(pos + 1, True)
                    if rest is not None:
                        return [c] + rest
            return None  # can't place any digit >= d
        else:
            return [digits[0]] * (length - pos)

    # Handle leading zero: first digit must be non-zero
    valid_digits = [c for c in digits if c != '0']
    if not valid_digits:
        return None

    # First digit must be from valid_digits (no leading zero)
    d = n_str[0]
    for c in valid_digits:
        if c > d:
            return c + digits[0] * (length - 1)
        elif c == d:
            rest = solve(1, True)
            if rest is not None:
                return c + ''.join(rest)
    return None

def find_min(n, k):
    n_str = str(n)
    best = None

    from itertools import combinations

    all_digits = [str(i) for i in range(10)]

    for combo in combinations(all_digits, k):
        digits = list(combo)
        # Try same length
        res = min_kbeautiful_with_digits(n_str, digits)
        if res is None:
            # Try length+1
            non_zero = [c for c in digits if c != '0']
            if non_zero:
                res = non_zero[0] + digits[0] * len(n_str)
        if res is not None:
            if best is None or int(res) < int(best):
                best = res

    return int(best)

